// Aggregate Salesforce sources into fact_channel_daily rows
// at campaign + region + date grain. Mappings confirmed from CWSI SF (11 Jun).
const campaigns = $('SF: Get Campaigns').all().map((i) => i.json);
const opps = $('SF: Get Opportunities').all().map((i) => i.json);
const leads = $('SF: Get Leads').all().map((i) => i.json);
const members = $('SF: Get CampaignMembers').all().map((i) => i.json);

// REGION: Account.BillingCountry (opps) / Lead.Country (leads) -> dashboard region
function regionFromCountry(country) {
  const c = String(country || '').trim().toLowerCase();
  if (['united kingdom','uk','gb','great britain','ireland','ie','guernsey','jersey','isle of man'].includes(c)) return 'UKI';
  if (['belgium','be','luxembourg','lu'].includes(c)) return 'BeLux';
  if (['netherlands','nl','the netherlands','holland'].includes(c)) return 'NL';
  return 'UNASSIGNED';
}

const CHANNEL_BY_TYPE = {
  'Event': 'Events & Webinars',
  'Webinar': 'Events & Webinars',
  'Seminar / Conference': 'Events & Webinars',
  'Email': 'Email',
  'Inbound Web': 'Organic SEO',
  'Content/White Paper': 'Organic SEO',
  // TODO(confirm w/ Margot): paid social vs paid search vs organic social
  'Advertisement': 'LinkedIn Paid',
  'Banner Ads': 'LinkedIn Paid',
  'Social Media': 'LinkedIn Paid'
};
// Fallback for Telemarketing / Partners / Referral / Other / blank (no dashboard channel)
function channelForType(type) { return CHANNEL_BY_TYPE[type] || 'Organic SEO'; }

const MQL_STATUS = 'Marketing Qualified Lead';
const UNQUALIFIED = ['Unqualified opp']; // 5% stage = not a real SQL

const campaignTypeById = {};
for (const c of campaigns) campaignTypeById[c.Id] = c.Type;

const leadById = {};
for (const l of leads) leadById[l.Id] = { status: l.Status, country: l.Country };

const agg = {};
function rowFor(campaignKey, region, date) {
  const key = campaignKey + '|' + region + '|' + date;
  if (!agg[key]) {
    agg[key] = {
      campaign_key: campaignKey, region_code: region,
      channel_name: channelForType(campaignTypeById[campaignKey]),
      pillar_name: '', // TODO: pillar not derivable from Campaign.Type; needs name parse or custom field
      activity_date: date, source: 'salesforce',
      spend: 0, impressions: 0, leads: 0, mql_count: 0,
      sql_count: 0, pipeline_value: 0, closed_won_value: 0
    };
  }
  return agg[key];
}

// LEADS + MQL  <- CampaignMember (campaign attribution) joined to Lead
for (const m of members) {
  if (!m.CampaignId || !m.LeadId) continue;
  const date = String(m.CreatedDate || '').slice(0, 10);
  if (!date) continue;
  const lead = leadById[m.LeadId] || {};
  const r = rowFor(m.CampaignId, regionFromCountry(lead.country), date);
  r.leads += 1;
  if (lead.status === MQL_STATUS) r.mql_count += 1;
}

// SQL + PIPELINE + CLOSED-WON  <- Opportunities
for (const o of opps) {
  if (!o.CampaignId) continue;
  // closed opps dated by CloseDate; open opps by CreatedDate
  const date = String((o.IsClosed ? o.CloseDate : o.CreatedDate) || o.CreatedDate || '').slice(0, 10);
  if (!date) continue;
  const country = o.Account && o.Account.BillingCountry;
  const r = rowFor(o.CampaignId, regionFromCountry(country), date);
  const amount = Number(o.Amount) || 0;
  const qualified = !UNQUALIFIED.includes(o.StageName);
  if (qualified) r.sql_count += 1;                 // every qualified opp = an SQL
  if (o.IsWon) r.closed_won_value += amount;        // won revenue
  else if (qualified && !o.IsClosed) r.pipeline_value += amount; // open qualified pipeline
}

// spend & impressions are NOT in Salesforce -> stay 0 here (filled by T-3: spend sheet / LinkedIn)
return Object.values(agg).map((json) => ({ json }));

const CHANNEL_BY_TYPE = {
  'Event': 'Events & Webinars',
  'Webinar': 'Events & Webinars',
  'Seminar / Conference': 'Events & Webinars',
  'Email': 'Email',
  'Inbound Web': 'Organic SEO',
  'Content/White Paper': 'Organic SEO',
  // TODO(confirm w/ Margot): paid social vs paid search vs organic social
  'Advertisement': 'LinkedIn Paid',
  'Banner Ads': 'LinkedIn Paid',
  'Social Media': 'LinkedIn Paid'
};
// Fallback for Telemarketing / Partners / Referral / Other / blank (no dashboard channel)
function channelForType(type) { return CHANNEL_BY_TYPE[type] || 'Organic SEO'; }

// Map Salesforce Campaign records to dim_campaign rows.
return $input.all().map((i) => {
  const c = i.json;
  return { json: {
    campaign_key: c.Id,
    campaign_name: c.Name || null,
    channel_name: channelForType(c.Type),
    source_system: 'salesforce'
  }};
});
